def p(g,R=range(9),S=[]):
 S[:]=[(r%3,c%3)for r in R for c in R if g[r][c]]
 return[[max(sum(g,[]))*((r//3,c//3)in S)*((r%3,c%3)in S)for c in R]for r in R]

def p(g,R=range(9),v=None):
 if v is None: v=max(sum(g,[]))
 S=[(r%3,c%3)for r in R for c in R if g[r][c]]
 return[[v*((r//3,c//3)in S)*((r%3,c%3)in S)for c in R]for r in R]
